import vex
import dspy

class SecureAuthAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.auth_check = dspy.ChainOfThought('request -> auth_decision')

    @vex.verify('auth_decision contains "token validated" or "access denied"')
    def forward(self, request):
        return self.auth_check(request=request)

# Optimized usage
agent = SecureAuthAgent()
optimized_agent = dspy.optimize.bootstrap(...)
response = optimized_agent(request='access /admin')

class RBACAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.rbac_check = dspy.Assert(
            'role in ["admin", "user"] and resource matches role permissions',
            'RBAC_violation'
        )

    def forward(self, user_role, resource):
        pred = dspy.ChainOfThought(f'role: {user_role}, resource: {resource} -> access')
        self.rbac_check(pred.access)
        return pred

agent = RBACAgent().inspect_modules()
